#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX_N 5
#define MAX_H 3
#define MAX_Q 5

// Function to find the minimum cost subset T
int find_min_cost_subset(int *S, int k, int X, int **C, int H, int **G, int N) {
    int min_cost = INT_MAX;
    for (int i = 0; i < (1 << k); i++) {
        int cost = 0;
        int count = 0;
        for (int j = 0; j < k; j++) {
            if ((i & (1 << j)) != 0) {
                count++;
                for (int p = 0; p < k; p++) {
                    for (int q = p; q < k; q++) {
                        if (G[S[j]][S[p]] != 0 && G[S[j]][S[q]] != 0) {
                            cost += C[S[p]][S[q]];
                        }
                    }
                }
            }
        }
        if (count == X && cost < min_cost) {
            min_cost = cost;
        }
    }
    return min_cost;
}

int main() {
    int N, H, Q;
    scanf("%d %d", &N, &H);
    int **G = (int **)malloc(N * sizeof(int *));
    for (int i = 0; i < N; i++) {
        G[i] = (int *)malloc(N * sizeof(int));
    }
    for (int i = 0; i < N - 1; i++) {
        int a, b;
        scanf("%d %d", &a, &b);
        G[a - 1][b - 1] = 1;
        G[b - 1][a - 1] = 1;
    }
    int **C = (int **)malloc(H * sizeof(int *));
    for (int i = 0; i < H; i++) {
        C[i] = (int *)malloc(H * sizeof(int));
    }
    for (int i = 0; i < H; i++) {
        for (int j = 0; j < H; j++) {
            scanf("%d", &C[i][j]);
        }
    }
    scanf("%d", &Q);
    for (int i = 0; i < Q; i++) {
        int k, X;
        scanf("%d %d", &k, &X);
        int *S = (int *)malloc(k * sizeof(int));
        for (int j = 0; j < k; j++) {
            scanf("%d", &S[j]);
            S[j]--;
        }
        int min_cost = find_min_cost_subset(S, k, X, C, H, G, N);
        if (min_cost == INT_MAX) {
            printf("No\n");
        } else {
            printf("%d\n", min_cost);
        }
        free(S);
    }
    for (int i = 0; i < N; i++) {
        free(G[i]);
    }
    free(G);
    for (int i = 0; i < H; i++) {
        free(C[i]);
    }
    free(C);
    return 0;
}

